    private void displayAllBTNActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_displayAllBTNActionPerformed
       Sound s = new Sound();
       s.OptionSound();
        V v = new V();
        BankFunction BF = new BankFunction();
        String loginAcc = v.getName();
        String role = v.getRole();
        String InputAccID = textField_InputID.getText();
        
        DefaultTableModel table = (DefaultTableModel)historyTable2.getModel();
        String databaseURL = "jdbc:ucanaccess://C:\\Users\\User\\Documents\\NetBeansProjects\\UNION BANK SYSTEM\\src\\database\\Userdb.accdb";
            try (Connection connection = DriverManager.getConnection(databaseURL)) {
               System.out.println("connected");
               String cs = "SELECT * from Transaction WHERE acc_out = ?";
               PreparedStatement us = connection.prepareStatement(cs);               
                us.setString(1,InputAccID);
                ResultSet rs = us.executeQuery();
                while(rs.next()){
                    int ID = rs.getInt("transactionID");
                    String in = rs.getString("acc_in");
                    String nmIn=BF.UIDconvertName(connection,in);
                    String out = rs.getString("acc_out");
                    String nmOut=BF.UIDconvertName(connection,out);
                    String bank = rs.getString("bank");
                    double amt = rs.getDouble("amount");
                    String date = rs.getString("transactionTime");
                   
                    Object[] row={ID,in,nmIn,out,nmOut,bank,amt,date};
                    
                    table.addRow(row);

                }
                rs.close();
                us.close();
            }catch (Exception e){
                System.err.println("Got an exception!");

                e.printStackTrace();

                System.out.println(e);
            }
            TableRowSorter<DefaultTableModel> sorter = new TableRowSorter<>(table);
            historyTable2.setRowSorter(sorter);
            sorter.setSortKeys(java.util.Collections.singletonList(new javax.swing.RowSorter.SortKey(0, javax.swing.SortOrder.ASCENDING)));
        

    }//GEN-LAST:event_displayAllBTNActionPerformed

